InterceptorScript.Source:
import java.util.Date;
import sailpoint.tools.Util;
import sailpoint.object.WorkItem;

import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

Log log = LogFactory.getLog("com.test.workflow");
String workflowName = "Workflow-User-Transfer";
log.info("Workflow :: "+workflowName+" :: InterceptorScript HR Approval Started");
if(null != item) {
log.info("item :: "+item+" :: item xml :: " +item.toXml());		

if(item.getState() == null){

Date expirationDate = Util.incrementDateByMinutes(new Date(),7200);
log.info("Workflow :: "+workflowName+" :: expirationDate :: "+expirationDate);

if(null != expirationDate) {
item.setExpiration(expirationDate);
item.setWakeUpDate(expirationDate);
context.saveObject(item);
context.commitTransaction();
}
} else{

String workItemState = item.getState().toString();
log.info("Workflow :: "+workflowName+" :: workItemState :: "+workItemState);
workflow.put("HRApprovalWorkitemState", workItemState);

}

log.info("Workflow :: "+workflowName+" :: HRApprovalWorkitemID :: "+item.getId());
workflow.put("HRApprovalWorkitemID", item.getId());
}

log.info("Workflow :: "+workflowName+" :: InterceptorScript HR Approval Ended");

