if(null != HRApprovalWorkitemState @and HRApprovalWorkitemState.equals("Expired")) {
log.info("Workflow :: "+workflowName+" :: Transition to Validation Step 1 :: return true");
log.info("Workflow :: "+workflowName+" :: Transition to Validation Step 1 Ended");
return true;
}

return false;

log.info("Workflow :: "+workflowName+" :: Transition to Validation Step 1 Ended");

